const D="聊天陪伴";function S(a){const n=Date.now()-a;if(n<0){const e=new Date(a);return`${String(e.getMonth()+1).padStart(2,"0")}-${String(e.getDate()).padStart(2,"0")}`}if(n<6e4)return"刚刚";if(n<60*6e4)return Math.floor(n/6e4)+" 分钟前";const t=new Date(a),o=new Date,g=e=>new Date(e.getFullYear(),e.getMonth(),e.getDate()).getTime(),r=Math.floor((g(o)-g(t))/(24*3600*1e3)),i=String(t.getHours()).padStart(2,"0"),s=String(t.getMinutes()).padStart(2,"0");if(r===0)return`今天 ${i}:${s}`;if(r===1)return`昨天 ${i}:${s}`;if(r<7)return`${r} 天前`;const u=t.getFullYear()===o.getFullYear(),f=`${String(t.getMonth()+1).padStart(2,"0")}-${String(t.getDate()).padStart(2,"0")}`;return u?f:`${t.getFullYear()}-${f}`}export{D as C,S as f};
